const body = $input.first().json.body || {};
const events = Array.isArray(body.events) ? body.events : [];

const ddl = "CREATE TABLE IF NOT EXISTS dashboard_auth_events (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, occurred_at DATETIME NOT NULL, src_ip VARCHAR(45) NOT NULL, method VARCHAR(10), path VARCHAR(512), status SMALLINT NOT NULL, user_agent VARCHAR(512), had_auth TINYINT NOT NULL DEFAULT 0, bytes_sent INT, line_hash CHAR(64) NOT NULL UNIQUE, INDEX idx_occurred (occurred_at), INDEX idx_src_ip (src_ip), INDEX idx_status (status)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4";

if (events.length === 0) {
  return [{ json: { sql: ddl + '; SELECT 0 AS inserted', eventCount: 0 } }];
}

const esc = (v) => {
  if (v === null || v === undefined) return 'NULL';
  return "'" + String(v).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'";
};

const values = events.map(e => {
  return `(${esc(e.occurred_at)}, ${esc(e.src_ip)}, ${esc(e.method)}, ${esc(e.path)}, ${Number(e.status) || 0}, ${esc(e.user_agent)}, ${e.had_auth ? 1 : 0}, ${Number.isFinite(e.bytes_sent) ? e.bytes_sent : 'NULL'}, ${esc(e.line_hash)})`;
}).join(',\n');

const insert = `INSERT IGNORE INTO dashboard_auth_events (occurred_at, src_ip, method, path, status, user_agent, had_auth, bytes_sent, line_hash) VALUES ${values}`;

return [{ json: { sql: ddl + ';\n' + insert, eventCount: events.length } }];

const rows = $input.all().map(i => i.json).filter(r => r && r.occurred_at);

// ---- Classification helpers ----
// RFC1918 + loopback + IPv6 link-local + IPv6 ULA (fc00::/7)
const isInternalIp = (ip) => {
  if (!ip) return false;
  if (ip === '::1' || ip.startsWith('127.')) return true;
  if (ip.startsWith('10.') || ip.startsWith('192.168.')) return true;
  if (/^172\.(1[6-9]|2\d|3[01])\./.test(ip)) return true;
  const lc = ip.toLowerCase();
  if (lc.startsWith('fe80:')) return true;
  if (/^f[cd][0-9a-f]{2}:/.test(lc)) return true;
  return false;
};

// Static assets that browsers (notably iOS Safari) fetch without Authorization header.
// A 401 here reflects browser quirk, not an auth attempt. Match any path whose final
// segment has a recognized static-asset extension, with optional query string.
const staticAssetRe = /\.(?:js|mjs|cjs|css|map|png|jpe?g|svg|gif|webp|woff2?|ttf|ico|json|webmanifest|txt)(?:\?.*)?$/i;

// Monitoring agents that probe with credential-less HEAD/GET. Not attacks on their own —
// but only benign when they hit root or standard health-check paths. A "curl" UA hitting
// /.env or /wp-login.php is an attacker using curl, not a monitor.
// First-load hits to the app entry paths. iOS Safari and link-preview crawlers
// produce credential-less 401s here on every fresh session (not attacks).
const sessionEntryRe = /^(\/|\/dashboard\/?|\/dashboard\/events)$/i;
const probeUaRe = /^(Zabbix\b|ansible-httpget\b|curl\b|Wget\b|Python-urllib\b|Go-http-client\b)/i;
const monitorPathRe = /^\/(health|healthz|status|ping|readyz|livez)?$/i;

const classify = (r) => {
  if (r.had_auth) return 'real_attempt';
  const isMonitorPath = r.path && monitorPathRe.test(r.path);
  const isProbeUa = r.user_agent && probeUaRe.test(r.user_agent);
  if (isMonitorPath && isProbeUa) return 'monitor_probe';
  if (r.path && (staticAssetRe.test(r.path) || sessionEntryRe.test(r.path))) return 'asset_probe';
  return 'endpoint_probe';
};

for (const r of rows) {
  r.classification = classify(r);
  r.is_internal = isInternalIp(r.src_ip);
}

const buildByIp = (subset) => {
  const byIp = new Map();
  for (const r of subset) {
    let e = byIp.get(r.src_ip);
    if (!e) {
      e = {
        ip: r.src_ip, is_internal: r.is_internal,
        count: 0, real_attempts: 0, probes: 0,
        asset_probes: 0, monitor_probes: 0, endpoint_probes: 0,
        user_agents: new Set(),
        first_seen: r.occurred_at, last_seen: r.occurred_at
      };
      byIp.set(r.src_ip, e);
    }
    e.count++;
    if (r.classification === 'real_attempt') e.real_attempts++;
    else {
      e.probes++;
      if (r.classification === 'asset_probe') e.asset_probes++;
      else if (r.classification === 'monitor_probe') e.monitor_probes++;
      else e.endpoint_probes++;
    }
    if (r.user_agent) e.user_agents.add(r.user_agent);
    if (r.occurred_at < e.first_seen) e.first_seen = r.occurred_at;
    if (r.occurred_at > e.last_seen) e.last_seen = r.occurred_at;
  }
  return [...byIp.values()]
    .map(e => ({ ...e, user_agents: [...e.user_agents].slice(0, 5) }))
    .sort((a, b) => b.count - a.count)
    .slice(0, 20);
};

const buildByPath = (subset) => {
  const m = new Map();
  for (const r of subset) {
    const k = r.path || '(none)';
    m.set(k, (m.get(k) || 0) + 1);
  }
  return [...m.entries()]
    .map(([path, count]) => ({ path, count }))
    .sort((a, b) => b.count - a.count)
    .slice(0, 10);
};

const countBy = (subset, cls) => subset.filter(r => r.classification === cls).length;

const total = rows.length;
const real_attempts = countBy(rows, 'real_attempt');
const asset_probes = countBy(rows, 'asset_probe');
const monitor_probes = countBy(rows, 'monitor_probe');
const endpoint_probes = countBy(rows, 'endpoint_probe');
const probes = total - real_attempts;

const external = rows.filter(r => !r.is_internal);
const internal = rows.filter(r => r.is_internal);

// What a human (or voice agent) should actually headline: external IPs that were
// either trying credentials or poking at non-static endpoints.
const concerning = external.filter(r =>
  r.classification === 'real_attempt' || r.classification === 'endpoint_probe'
);

const recent = rows.slice(0, 50).map(r => ({
  id: r.id, occurred_at: r.occurred_at, src_ip: r.src_ip,
  method: r.method, path: r.path, status: r.status,
  user_agent: r.user_agent, had_auth: !!r.had_auth,
  classification: r.classification, is_internal: r.is_internal
}));

return [{ json: {
  total, real_attempts, probes,
  by_ip: buildByIp(rows),
  by_path: buildByPath(rows),
  recent,
  window_days: 7,
  classification: { real_attempts, asset_probes, monitor_probes, endpoint_probes },
  external: {
    total: external.length,
    real_attempts: countBy(external, 'real_attempt'),
    endpoint_probes: countBy(external, 'endpoint_probe'),
    asset_probes: countBy(external, 'asset_probe'),
    monitor_probes: countBy(external, 'monitor_probe'),
    by_ip: buildByIp(external)
  },
  internal: {
    total: internal.length,
    real_attempts: countBy(internal, 'real_attempt'),
    endpoint_probes: countBy(internal, 'endpoint_probe'),
    asset_probes: countBy(internal, 'asset_probe'),
    monitor_probes: countBy(internal, 'monitor_probe'),
    by_ip: buildByIp(internal)
  },
  concerning: {
    total: concerning.length,
    by_ip: buildByIp(concerning)
  }
} }];

const rows = $input.all().map(i => i.json).filter(r => r && r.src_ip);
// Merge multiple user_agent rows per IP.
const byIp = new Map();
const PROBE_RE = /zabbix|ansible|prometheus|uptime[- ]?kuma|statuscake|pingdom/i;
for (const r of rows) {
  let e = byIp.get(r.src_ip);
  if (!e) { e = { ip: r.src_ip, count: 0, user_agents: new Set(), first_seen: r.first_seen, last_seen: r.last_seen, looks_like_probe: true }; byIp.set(r.src_ip, e); }
  e.count += Number(r.count) || 0;
  if (r.user_agent) e.user_agents.add(r.user_agent);
  if (r.first_seen < e.first_seen) e.first_seen = r.first_seen;
  if (r.last_seen > e.last_seen) e.last_seen = r.last_seen;
  if (!(r.user_agent && PROBE_RE.test(r.user_agent))) e.looks_like_probe = false;
}
const by_ip = [...byIp.values()]
  .map(e => ({ ...e, user_agents: [...e.user_agents].slice(0, 3) }))
  .sort((a, b) => b.count - a.count);

return [{ json: { window_minutes: 10, by_ip } }];

